1. using Microsoft.VisualStudio.TestTools.UnitTesting;
2. using AccessControl;
3. 
4. namespace AccessControl.Tests;
5. 
6. [TestClass]
7. public sealed class AccessCheckerTests
8. {
9.     // -- GetPermission tests --
10.     // Tests the happy path for Admin and User, but never checks Editor on system resources,
11.     // never verifies Guest access denial, and never checks CanWrite for User role.
12.     // A flip of CanRead/CanWrite for Editor+system would survive.
13.     // Removing the Guest denial branch would survive.
14. 
15.     [TestMethod]
16.     public void GetPermission_Admin_CanReadAndWrite()
17.     {
18.         var checker = new AccessChecker();
19.         var perm = checker.GetPermission(Role.Admin, "documents/report.pdf");
20.         Assert.IsTrue(perm.CanRead);
21.         Assert.IsTrue(perm.CanWrite);
22.     }
23. 
24.     [TestMethod]
25.     public void GetPermission_Admin_SystemResource_CanReadAndWrite()
26.     {
27.         var checker = new AccessChecker();
28.         var perm = checker.GetPermission(Role.Admin, "sys/config");
29.         Assert.IsTrue(perm.CanRead);
30.         Assert.IsTrue(perm.CanWrite);
31.     }
32. 
33.     [TestMethod]
34.     public void GetPermission_Editor_NormalResource_CanReadAndWrite()
35.     {
36.         var checker = new AccessChecker();
37.         var perm = checker.GetPermission(Role.Editor, "documents/report.pdf");
38.         Assert.IsTrue(perm.CanRead);
39.         Assert.IsTrue(perm.CanWrite);
40.     }
41. 
42.     [TestMethod]
43.     public void GetPermission_User_NormalResource_CanRead()
44.     {
45.         var checker = new AccessChecker();
46.         var perm = checker.GetPermission(Role.User, "documents/report.pdf");
47.         Assert.IsTrue(perm.CanRead);
48.     }
49. 
50.     [TestMethod]
51.     public void GetPermission_NullResource_Throws()
52.     {
53.         var checker = new AccessChecker();
54.         Assert.ThrowsException<ArgumentNullException>(
55.             () => checker.GetPermission(Role.Admin, null!));
56.     }
57. 
58.     // -- CanPerform tests --
59.     // Only tests the read path, never tests writeAccess=true.
60.     // A mutation flipping the ternary (writeAccess ? CanWrite : CanRead) would survive.
61. 
62.     [TestMethod]
63.     public void CanPerform_AdminRead_ReturnsTrue()
64.     {
65.         var checker = new AccessChecker();
66.         Assert.IsTrue(checker.CanPerform(Role.Admin, "documents/report.pdf", false));
67.     }
68. 
69.     [TestMethod]
70.     public void CanPerform_UserReadNormal_ReturnsTrue()
71.     {
72.         var checker = new AccessChecker();
73.         Assert.IsTrue(checker.CanPerform(Role.User, "documents/report.pdf", false));
74.     }
75. 
76.     // -- ElevateRole tests --
