arguments.new_str:
    [TestMethod]
    public void ElevateRole_UserToEditor_WithValidToken()
    {
        var checker = new AccessChecker();
        var result = checker.ElevateRole(Role.User, "ELEVATE-EDITOR");
        Assert.AreEqual(Role.Editor, result);
    }

    // --- Tests plugging the gaps found by mutation analysis ---

    // Mutation 1: Editor + system resource had no coverage
    [TestMethod]
    public void GetPermission_Editor_SystemResource_CanReadButNotWrite()
    {
        var checker = new AccessChecker();
        var perm = checker.GetPermission(Role.Editor, "sys/config");
        Assert.IsTrue(perm.CanRead);
        Assert.IsFalse(perm.CanWrite);
    }

    // Mutation 2: Guest / default branch had no coverage
    [TestMethod]
    public void GetPermission_Guest_NormalResource_NeitherReadNorWrite()
    {
        var checker = new AccessChecker();
        var perm = checker.GetPermission(Role.Guest, "documents/report.pdf");
        Assert.IsFalse(perm.CanRead);
        Assert.IsFalse(perm.CanWrite);
    }

    [TestMethod]
    public void GetPermission_Guest_SystemResource_NeitherReadNorWrite()
    {
        var checker = new AccessChecker();
        var perm = checker.GetPermission(Role.Guest, "sys/config");
        Assert.IsFalse(perm.CanRead);
        Assert.IsFalse(perm.CanWrite);
    }

    // User + system resource falls to default — verify denial
    [TestMethod]
    public void GetPermission_User_SystemResource_NeitherReadNorWrite()
    {
        var checker = new AccessChecker();
        var perm = checker.GetPermission(Role.User, "sys/config");
        Assert.IsFalse(perm.CanRead);
        Assert.IsFalse(perm.CanWrite);
    }

    // Mutation 3: User CanWrite was never asserted
    [TestMethod]
    public void GetPermission_User_NormalResource_CannotWrite()
    {
        var checker = new AccessChecker();
        var perm = checker.GetPermission(Role.User, "documents/report.pdf");
        Assert.IsTrue(perm.CanRead);
        Assert.IsFalse(perm.CanWrite);
    }

    // Mutation 5: CanPerform write path was never tested
    [TestMethod]
    public void CanPerform_AdminWrite_ReturnsTrue()
    {
        var checker = new AccessChecker();
        Assert.IsTrue(checker.CanPerform(Role.Admin, "documents/report.pdf", true));
    }

    [TestMethod]
    public void CanPerform_UserWriteNormal_ReturnsFalse()
    {
        var checker = new AccessChecker();
        Assert.IsFalse(checker.CanPerform(Role.User, "documents/report.pdf", true));
    }

    [TestMethod]
    public void CanPerform_GuestRead_ReturnsFalse()
    {
        var checker = new AccessChecker();
        Assert.IsFalse(checker.CanPerform(Role.Guest, "documents/report.pdf", false));
    }

    // Mutation 6: Null/empty token guard was never tested
    [TestMethod]
    public void ElevateRole_NullToken_ReturnsOriginalRole()
    {
        var checker = new AccessChecker();
        Assert.AreEqual(Role.User, checker.ElevateRole(Role.User, null));
    }

    [TestMethod]
    public void ElevateRole_EmptyToken_ReturnsOriginalRole()
    {
        var checker = new AccessChecker();
        Assert.AreEqual(Role.User, checker.ElevateRole(Role.User, ""));
    }

    [TestMethod]
    public void ElevateRole_InvalidToken_ReturnsOriginalRole()
    {
        var checker = new AccessChecker();
        Assert.AreEqual(Role.Editor, checker.ElevateRole(Role.Editor, "BOGUS"));
    }

    // Mutation 7: Guest should NOT be elevated to Editor
    [TestMethod]
    public void ElevateRole_Guest_CannotElevateToEditor()
    {
        var checker = new AccessChecker();
        Assert.AreEqual(Role.Guest, checker.ElevateRole(Role.Guest, "ELEVATE-EDITOR"));
    }

    // Mutation 8: User should NOT be elevated to Admin
    [TestMethod]
    public void ElevateRole_User_CannotElevateToAdmin()
    {
        var checker = new AccessChecker();
        Assert.AreEqual(Role.User, checker.ElevateRole(Role.User, "ELEVATE-ADMIN"));
    }
}

